1	export type Item = {
2	  type: string;
3	  material?: string;
4	  enchantment?: number;
5	  cursed?: boolean;
6	};
7	
8	export type QuoteStep = {
9	  op: "quote";
10	  items: Item[];
11	};
12	
13	export type Damage = { itemType: string; amount: number };
14	
15	export type ClaimStep = {
16	  op: "claim";
17	  policy: number;
18	  incident: { cause: string; damages: Damage[] };
19	};
20	
21	export type Step = QuoteStep | ClaimStep;
22	
23	export type Scenario = {
24	  customer: { yearsWithMHPCO: number };
25	  steps: Step[];
26	};
27	
28	export type QuoteResult = { premium: number };
29	export type ClaimResult = { payout: number; remainingCap: number };
30	export type StepResult = QuoteResult | ClaimResult;
31	
32	export type ScenarioResult = {
33	  results: StepResult[];
34	};
35	
36	// Quote constants
37	const PROCESSING_FEE = 5;
38	const FIRST_CONTRACT_SURCHARGE_RATE = 0.1;
39	const FOLLOW_UP_CONTRACT_DISCOUNT_RATE = 0.15;
40	const BLOCK_OF_THREE_DISCOUNT = 15;
41	const CURSE_SURCHARGE_RATE = 0.5;
42	const HIGH_ENCHANTMENT_SURCHARGE_THRESHOLD = 5;
43	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
44	const LOYALTY_YEARS_THRESHOLD = 2;
45	const LOYALTY_DISCOUNT_RATE = 0.2;
46	
47	type CatalogEntry = { basePremium: number; insuranceValue: number };
48	
49	const ITEM_CATALOG: Record<string, CatalogEntry> = {
50	  sword: { basePremium: 100, insuranceValue: 1000 },
51	  amulet: { basePremium: 60, insuranceValue: 600 },
52	  staff: { basePremium: 80, insuranceValue: 800 },
53	  potion: { basePremium: 40, insuranceValue: 400 },
54	  rune: { basePremium: 25, insuranceValue: 250 },
55	  moonstone: { basePremium: 25, insuranceValue: 250 },
56	};
57	
58	const catalogEntryFor = (type: string): CatalogEntry => {
59	  const entry = ITEM_CATALOG[type];
60	  if (!entry) {
61	    throw new Error(`Unknown item type: ${type}`);
62	  }
63	  return entry;
64	};
65	
66	// Claim constants
67	const DEDUCTIBLE = 100;
68	const CAP_MULTIPLIER = 2;
69	const HIGH_ENCHANTMENT_PAYOUT_THRESHOLD = 8;
70	const HIGH_ENCHANTMENT_PAYOUT_RATE = 0.5;
71	
72	const BLOCK_OF_THREE_ELIGIBLE_TYPES = ["rune", "moonstone"];
73	
74	const blockOfThreeDiscount = (alikeComponentCount: number): number =>
75	  alikeComponentCount === 3 ? BLOCK_OF_THREE_DISCOUNT : 0;
76	
77	const countItemsOfType = (items: Item[], type: string): number =>
78	  items.filter((item) => item.type === type).length;
79	
80	const enchantmentLevel = (item: Item): number => item.enchantment ?? 0;
81	
82	const isCursed = (item: Item): boolean => item.cursed === true;
83	const qualifiesForHighEnchantmentSurcharge = (item: Item): boolean =>
84	  enchantmentLevel(item) >= HIGH_ENCHANTMENT_SURCHARGE_THRESHOLD;
85	
86	type Rule<T> = { applies: (input: T) => boolean; rate: number };
87	
88	const sumApplicableRates = <T>(
89	  rules: ReadonlyArray<Rule<T>>,
90	  input: T,
91	  base: number,
92	): number =>
93	  rules.reduce((sum, { applies, rate }) => sum + (applies(input) ? base * rate : 0), 0);
94	
95	const ITEM_SURCHARGE_RATES: ReadonlyArray<Rule<Item>> = [
96	  { applies: isCursed, rate: CURSE_SURCHARGE_RATE },
97	  { applies: qualifiesForHighEnchantmentSurcharge, rate: HIGH_ENCHANTMENT_SURCHARGE_RATE },
98	];
99	
100	const basePremiumFor = (item: Item): number => catalogEntryFor(item.type).basePremium;
101	
102	const surchargesForItem = (item: Item): number =>
103	  sumApplicableRates(ITEM_SURCHARGE_RATES, item, basePremiumFor(item));
104	
105	const sumItemSpecificSurcharges = (items: Item[]): number =>
106	  items.reduce((sum, item) => sum + surchargesForItem(item), 0);
107	
108	const blockOfThreeDiscountTotal = (items: Item[]): number =>
109	  BLOCK_OF_THREE_ELIGIBLE_TYPES.reduce(
110	    (sum, type) => sum + blockOfThreeDiscount(countItemsOfType(items, type)),
111	    0,
112	  );
113	
114	const basePremiumForItems = (items: Item[]): number =>
115	  items.reduce((sum, item) => sum + basePremiumFor(item), 0) -
116	  blockOfThreeDiscountTotal(items);
117	
118	type QuoteContext = { customer: Scenario["customer"]; isFollowUp: boolean };
119	
120	// Positive rate = surcharge, negative = discount.
121	const POLICY_ADJUSTMENTS: ReadonlyArray<Rule<QuoteContext>> = [
122	  { applies: () => true, rate: FIRST_CONTRACT_SURCHARGE_RATE },
123	  {
124	    applies: (ctx) => ctx.customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD,
125	    rate: -LOYALTY_DISCOUNT_RATE,
126	  },
127	  { applies: (ctx) => ctx.isFollowUp, rate: -FOLLOW_UP_CONTRACT_DISCOUNT_RATE },
128	];
129	
130	const sumPolicyAdjustments = (basePremium: number, ctx: QuoteContext): number =>
131	  sumApplicableRates(POLICY_ADJUSTMENTS, ctx, basePremium);
132	
133	// MHPCO always rounds in its own favor: charge a bit more, pay out a bit less.
134	const roundPremiumInFavorOfInsurer = Math.ceil;
135	const roundPayoutInFavorOfInsurer = Math.floor;
136	
137	const quote = (
138	  step: QuoteStep,
139	  customer: Scenario["customer"],
140	  isFollowUp: boolean,
141	): QuoteResult => {
142	  const basePremium = basePremiumForItems(step.items);
143	  const itemSurcharges = sumItemSpecificSurcharges(step.items);
144	  const policyAdjustments = sumPolicyAdjustments(basePremium, { customer, isFollowUp });
145	  const premium = roundPremiumInFavorOfInsurer(
146	    basePremium + itemSurcharges + policyAdjustments + PROCESSING_FEE,
147	  );
148	  return { premium };
149	};
150	
151	type Policy = { items: Item[]; cap: number };
152	
153	const insuranceSumOf = (items: Item[]): number =>
154	  items.reduce((sum, item) => sum + catalogEntryFor(item.type).insuranceValue, 0);
155	
156	const initialCapFor = (items: Item[]): number => insuranceSumOf(items) * CAP_MULTIPLIER;
157	
158	const findInsuredItem = (policy: Policy, itemType: string): Item => {
159	  const item = policy.items.find((item) => item.type === itemType);
160	  if (!item) {
161	    throw new Error(`No insured item of type ${itemType} in policy`);
162	  }
163	  return item;
164	};
165	
166	const qualifiesForHighEnchantmentPayoutReduction = (item: Item): boolean =>
167	  enchantmentLevel(item) >= HIGH_ENCHANTMENT_PAYOUT_THRESHOLD;
168	
169	const payoutForDamage = (damage: Damage, insuredItem: Item): number => {
170	  const reimbursable = qualifiesForHighEnchantmentPayoutReduction(insuredItem)
171	    ? damage.amount * HIGH_ENCHANTMENT_PAYOUT_RATE
172	    : damage.amount;
173	  return Math.max(0, reimbursable - DEDUCTIBLE);
174	};
175	
176	const countDamagesByType = (damages: Damage[]): Map<string, number> =>
177	  damages.reduce((counts, dmg) => {
178	    counts.set(dmg.itemType, (counts.get(dmg.itemType) ?? 0) + 1);
179	    return counts;
180	  }, new Map<string, number>());
181	
182	const assertDamagesWithinPolicy = (damages: Damage[], policy: Policy): void => {
183	  for (const [itemType, count] of countDamagesByType(damages)) {
184	    if (count > countItemsOfType(policy.items, itemType)) {
185	      throw new Error(`Damage count for ${itemType} exceeds insured quantity`);
186	    }
187	  }
188	};
189	
190	const claim = (step: ClaimStep, policy: Policy): ClaimResult => {
191	  assertDamagesWithinPolicy(step.incident.damages, policy);
192	  const grossPayout = step.incident.damages.reduce(
193	    (sum, dmg) => sum + payoutForDamage(dmg, findInsuredItem(policy, dmg.itemType)),
194	    0,
195	  );
196	  const cappedPayout = Math.min(grossPayout, policy.cap);
197	  return {
198	    payout: roundPayoutInFavorOfInsurer(cappedPayout),
199	    remainingCap: policy.cap - cappedPayout,
200	  };
201	};
202	
203	const handleQuoteStep = (
204	  step: QuoteStep,
205	  customer: Scenario["customer"],
206	  policies: Policy[],
207	): QuoteResult => {
208	  const isFollowUp = policies.length > 0;
209	  const result = quote(step, customer, isFollowUp);
210	  policies.push({ items: step.items, cap: initialCapFor(step.items) });
211	  return result;
212	};
213	
214	const handleClaimStep = (step: ClaimStep, policies: Policy[]): ClaimResult => {
215	  const policy = policies[step.policy];
216	  const result = claim(step, policy);
217	  policy.cap = result.remainingCap;
218	  return result;
219	};
220	
221	export const runScenario = (scenario: Scenario): ScenarioResult => {
222	  const policies: Policy[] = [];
223	  const results: StepResult[] = scenario.steps.map((step) =>
224	    step.op === "quote"
225	      ? handleQuoteStep(step, scenario.customer, policies)
226	      : handleClaimStep(step, policies),
227	  );
228	  return { results };
229	};
